import React, { useState } from 'react';

const Journal = () => {
  const [title, setTitle] = useState('');
  const [date, setDate] = useState('');
  const [entry, setEntry] = useState('');

  function handleAnalyze() {
    // placeholder for analyze functionality
    console.log({ title, date, entry });
  }

  return (
    <div className="journal-page">
      <h1 className="journal-heading">Journal Page</h1>

      <div className="journal-header">
        <input
          className="journal-title"
          placeholder="Title (optional)"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />
        <input
          className="journal-date"
          placeholder="dd/mm/yyyy"
          value={date}
          onChange={(e) => setDate(e.target.value)}
        />
      </div>

      <div className="journal-body">
        <textarea
          className="journal-entry"
          placeholder="Write your journal entry here..."
          value={entry}
          onChange={(e) => setEntry(e.target.value)}
        />
      </div>

      <div className="journal-footer">
        <button className="journal-analyze" onClick={handleAnalyze}>
          Analyze
        </button>
      </div>

      <Stylesheet />
    </div>
  );
};

const Stylesheet = () => {
  return (
    <style>{`
      .journal-page {
        padding: 4rem;
        font-family: 'Cedarville Cursive', cursive;
        color: var(--text);
      }

      .journal-heading {
        font-size: 2.5rem;
        margin-bottom: 1.5rem;
        text-align: center;
      }

      .journal-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        gap: 1rem;
        margin-bottom: 1rem;
      }

      .journal-title,
      .journal-date {
        background-color: var(--secondary-color);
        border: none;
        padding: 10px;
        border-radius: 5px;
        font-size: 1.2rem;
        color: var(--text);
        font-family: 'Cedarville Cursive', cursive;
      }

      .journal-title {
        flex: 2;
      }

      .journal-date {
        flex: 1;
      }

      .journal-body {
        margin-top: 1rem;
        margin-bottom: 2rem;
      }

      .journal-entry {
        width: 100%;
        min-height: 300px;
        background-color: var(--secondary-color);
        border: none;
        padding: 15px;
        border-radius: 5px;
        font-size: 1.2rem;
        font-family: 'Cedarville Cursive', cursive;
        color: var(--text);
        resize: vertical;
        outline: none;
        box-sizing: border-box;
      }

      .journal-footer {
        display: flex;
        justify-content: center;
      }

      .journal-analyze {
        background-color: var(--button-color);
        border: none;
        padding: 10px 20px;
        border-radius: 5px;
        font-size: 1.5rem;
        color: var(--bg-parchment);
        font-family: 'Cedarville Cursive', cursive;
        cursor: pointer;
      }
    `}</style>
  );
};

export default Journal;
